from __future__ import annotations

import csv
from dataclasses import dataclass
from decimal import Decimal
from pathlib import Path


@dataclass(frozen=True)
class CustomerTotal:
    customer: str
    total: Decimal


def load_orders(path: str | Path) -> list[dict[str, str]]:
    with Path(path).open(newline="", encoding="utf-8") as handle:
        return list(csv.DictReader(handle))


def net_revenue_by_month(rows: list[dict[str, str]]) -> dict[str, Decimal]:
    totals: dict[str, Decimal] = {}
    for row in rows:
        month = row["date"][:7]
        amount = Decimal(row["amount"])
        if row["type"] == "refund":
            continue
        totals[month] = totals.get(month, Decimal("0")) + amount
    return totals


def top_customers(rows: list[dict[str, str]], limit: int = 3) -> list[CustomerTotal]:
    totals: dict[str, Decimal] = {}
    for row in rows:
        customer = row["customer"]
        amount = Decimal(row["amount"])
        totals[customer] = totals.get(customer, Decimal("0")) + amount
    ranked = sorted(totals.items(), key=lambda item: item[1], reverse=True)
    return [CustomerTotal(customer=name, total=total) for name, total in ranked[:limit]]

