from decimal import Decimal

from ledger_app.ledger import CustomerTotal, load_orders, net_revenue_by_month, top_customers


def test_net_revenue_counts_refunds_against_monthly_total() -> None:
    rows = load_orders("data/orders.csv")

    assert net_revenue_by_month(rows) == {
        "2026-05": Decimal("181.50"),
        "2026-06": Decimal("363.75"),
    }


def test_top_customers_counts_refunds_against_customer_total() -> None:
    rows = load_orders("data/orders.csv")

    assert top_customers(rows, limit=2) == [
        CustomerTotal("Globex", Decimal("275.50")),
        CustomerTotal("Initech", Decimal("173.75")),
    ]

