from __future__ import annotations

from dataclasses import dataclass
from datetime import date
from decimal import Decimal


@dataclass(frozen=True)
class Sale:
    day: date
    amount: Decimal


def filter_sales(rows: list[Sale], start: date, end: date) -> list[Sale]:
    return [row for row in rows if start <= row.day < end]


def total_sales(rows: list[Sale], start: date, end: date) -> Decimal:
    return sum((row.amount for row in filter_sales(rows, start, end)), Decimal("0"))

