from __future__ import annotations


def headings(markdown: str) -> list[str]:
    return [line[2:].strip() for line in markdown.splitlines() if line.startswith("## ")]


def update_toc(markdown: str) -> str:
    entries = "\n".join(f"- {heading}" for heading in headings(markdown))
    return markdown.replace("<!-- TOC -->", f"<!-- TOC -->\n{entries}")

